use super::*;
use common::components::{TiptapEditor, Typo, Variant, Weight};

#[component]
pub fn ViewerPage(space_id: SpacePartition) -> Element {
    let mut content = use_signal(|| {
        r#"<section><h1>I. 연구 개요</h1><ol><li><strong>연구 배경 및 필요성</strong><ul><li><strong>현안의 대두 및 입법 동향</strong><ul><li>강간죄 구성요건의 '동의 부재' 기준 전환에 대한 공론형 여론조사가 국회 입법조사처와 협력하여 진행됨.</li><li>블록체인 기반 공정한 정보 제공과 숙고된 토론을 통해 여론 형성 및 변화를 과학적으로 분석하고자 함.</li></ul></li><li><strong>쟁점의 복합성과 갈등 구조</strong><ul><li>법 개정만으로는 해결되지 않는 부분이 많고, 실제 피해자 지원과 피의자 인권 보장 사이 균형이 중요함.</li><li>증거 기준의 현실성과 디지털 증거의 수집 및 보존 절차의 일관성 확보가 필요함.</li><li>사회적으로 동의 문화의 정착과 동시에 교육 및 캠페인을 병행하여 실제 사건 감소와 인식 개선에 도움이 될 것으로 기대됨.</li></ul></li><li><strong>정책 결정의 딜레마와 숙고된 여론의 필요성</strong><ul><li>무고 우려를 줄이기 위해 수사 단계에서 사실관계 확인을 더 촘촘히 하고, 신고 접수 후 정황 증거와 진술의 일관성을 검토하는 장치 강화 필요함.</li><li>동의 기준의 모호함이 피해자 보호와 무고에 대한 불안을 커트리므로, 명확한 가이드라인 마련이 필요함.</li><li>예방 교육과 사후 지원 체계가 함께 가야 하며, 이를 통해 성폭력 예방과 피해자 지원의 효과적 실행을 기대함.</li></ul></li></ul></li><li><strong>연구 개요</strong><ul><li>국회 입법조사처와 협력하여 진행하는 블록체인 기반 공론형 여론조사로서, 강간죄 구성요건의 '동의 부재' 기준 전환에 대한 의견을 조사함.</li><li>공정한 정보 제공과 숙고된 토론을 통해 여론의 형성과 변화를 과학적으로 분석하여 입법 결정의 합리적 참고자료로 활용하는 목적으로 연구됨.</li><li>개인정보 보호 및 익명성은 DID 기반 보호, 암호화·분산형 관리, 익명 처리 및 연구 목적 사용, 블록체인 기록의 위·변조 방지로 보장됨.</li><li>법 개정만으로 해결되지 않는 부분이 많고, 실제 피해자 지원과 피의자 인권 보장 사이 균형이 중요하다고 보는 의견이 제시됨.</li><li>증거 기준의 현실성이 가장 큰 문제로 지적되고, 디지털 증거의 수집과 보존 절차가 일관되지 않으면 양쪽 모두에 불신이 생길 수 있으니 제도 설계가 필요하다고 논의됨.</li></ul></li><li><strong>조사 목적</strong><ul><li><strong>핵심 목적</strong><ul><li>공정한 정보 제공과 숙고된 토론을 통해 여론의 형성과 변화를 과학적으로 분석함.</li><li>입법 결정의 합리적 참고자료로 활용하기 위한 목적으로 조사 진행함.</li></ul></li><li><strong>방법론적 혁신</strong><ul><li>블록체인 기반 공론형 여론조사로 개인정보 보호 및 익명성 보장함.</li><li>DID 기반 보호, 암호화·분산형 관리, 익명 처리 및 연구 목적 사용, 블록체인 기록의 위·변조 방지로 참여자 보호함.</li></ul></li><li><strong>기대 성과</strong><ul><li>입법 결정에 활용될 과학적 분석 자료 제공함.</li><li>공정한 정보 제공과 숙고된 토론을 통한 여론 분석으로 사회적 합의 도출 지원함.</li></ul></li></ul></li></ol></section><section><h1>II. 조사 설계 및 데이터 수집</h1><ol><li><strong>조사 설계</strong><ul><li>조사 주제는 강간죄 구성요건의 '동의 부재' 기준 전환(비동의 간음죄) 도입에 대한 의견 수렴으로 설정됨.</li><li>조사 목적은 공정한 정보 제공과 숙고된 토론을 통해 여론의 형성과 변화를 과학적으로 분석하여 입법 결정의 합리적 참고자료로 활용하는 데 있음.</li><li>개인정보 보호 및 익명성은 DID 기반 보호, 암호화·분산형 관리, 익명 처리 및 연구 목적 사용, 블록체인 기록의 위·변조 방지로 보장됨.</li><li>참여자들은 불편하거나 심리적 어려움을 느끼면 언제든 참여를 중단할 수 있고 불이익은 없음.</li><li>디지털 증거가 핵심이 되어 일관된 수집과 보존 절차가 요구되고, 이를 보장하기 위한 제도 설계가 필요함.</li></ul></li><li><strong>여론조사 진행 절차</strong><ul><li><strong>온라인 의견 조사</strong><ul><li>블록체인 기반 공론형 여론조사로 참여자의 익명성과 개인정보 보호를 위한 DID 기반 보호, 암호화·분산형 관리 적용됨.</li></ul></li><li><strong>정보 제공</strong><ul><li>강간죄 구성요건의 '동의 부재' 기준 전환(비동의 간음죄) 도입에 대한 공정한 정보 제공됨.</li></ul></li><li><strong>비실시간 온라인 토의</strong><ul><li>참여자들이 자유롭게 의견을 표출하고 토론하는 공간 제공됨.</li><li>참여자들의 의견 중 동의 기준의 명확성, 무고 및 악용 우려 완화 방안 등이 논의됨.</li></ul></li><li><strong>사후 온라인 의견 조사</strong><ul><li>숙고된 토론 후 의견 변화 여부를 파악하기 위한 추가 의견 조사 실시됨.</li></ul></li><li><strong>데이터 종합 분석</strong><ul><li>수집된 여론 데이터를 종합 분석하여 여론의 형성과 변화를 과학적으로 분석함.</li><li>분석 결과는 입법 결정의 합리적 참고자료로 활용됨.</li></ul></li></ul></li><li><strong>블록체인 기술 적용 방안</strong><ul><li><strong>DID</strong><ul><li>개인정보 보호 및 익명성 보장을 위해 DID 기반 보호가 필요함.</li></ul></li><li><strong>무결성 보장</strong><ul><li>수집된 데이터의 무결성 및 위·변조 방지를 위해 블록체인 기술 활용함.</li></ul></li><li><strong>투명성 및 감사 가능성</strong><ul><li>조사 과정의 투명성 확보와 감사 가능성을 위해 블록체인의 특성을 활용함.</li></ul></li><li><strong>인센티브 지급 자동화/Smart Contract</strong><ul><li>참여자에 대한 인센티브 지급 과정의 자동화 및 투명성 확보를 위해 스마트 컨트랙트 활용함.</li></ul></li></ul></li><li><strong>분석 방법</strong><ul><li><strong>정량 분석</strong><ul><li>응답자들의 비동의 간음죄 도입에 대한 찬성, 반대, 유보 의견 비율을 통계적으로 분석함.</li></ul></li><li><strong>정성 분석</strong><ul><li>참여자들의 의견 내용을 분석하여 무고 및 악용 우려 완화를 위한 개선 방향을 도출함.</li><li>'동의'와 '무고' 키워드의 TF-IDF 값을 활용하여 주요 토픽 추출함.</li></ul></li><li><strong>통합 분석</strong><ul><li>정량적 결과와 정성적 분석 결과를 종합하여 입법 결정에 대한 합리적 참고자료로 활용함.</li></ul></li></ul></li></ol></section><section><h1>III. 분석 결과</h1><ol><li><strong>공론형 여론조사: 의견 변화 분석</strong><ul><li><strong>전체 의견 변화 추이</strong><ul><li>조사 초기에는 찬성, 반대, 유보 의견이 다양하게 존재함.</li><li>참여자들은 법 개정의 한계와 실제 지원 및 인권 보장의 균형 중요성을 강조함.</li><li>증거 기준의 현실성과 디지털 증거의 필요성에 대한 의견이 집중적으로 제시됨.</li><li>사회적 동의 문화의 정착과 함께 교육 및 캠페인의 중요성이 지적됨.</li></ul></li></ul></li><li><strong>분석 결과</strong><ul><li>사전 설문 문항에서 참여자들은 강간죄 구성요건의 '동의 부재' 기준 전환에 대한 다양한 의견을 제시함.</li><li>참여자들은 디지털 증거의 수집 및 보존 절차의 일관성과 제도적 설계의 필요성을 강조함.</li><li>사회적으로 동의 문화의 정착과 함께 법적 논의, 교육, 캠페인의 병행을 통한 실제 사건 감소와 인식 개선을 제안함.</li><li>법률적으로 동의와 부재의 명확한 가이드라인 제공의 필요성을 언급함.</li><li>예방 교육과 사후 지원 체계의 중요성을 강조함.</li></ul></li><li><strong>토론 내용 분석</strong><ul><li><strong>토론 분석_LDA</strong><ul><li>토픽 모델링 결과, '동의'와 '무고'가 주요 토픽으로 추출되어 토론 내용의 중심이 됨.</li><li>토픽1에서 '동의'가 높은 비중을 차지하여 토론 참여자들이 주로 동의의 개념과 관련 문제를 논의함.</li><li>토픽2에서 '무고'가 중요한 위치를 차지하며, 무고에 대한 우려와 해결 방안이 논의됨.</li><li>토픽 간 연결성에서 '동의'와 '무고' 사이에 높은 가중치로 연결되어 있어 이 두 키워드가 서로 밀접하게 관련되어 있음.</li><li>토론 내용이 법적 개념 이외에도 사회적 동의 문화의 정착과 같은 논의로 확장됨.</li></ul></li><li><strong>토론 분석_TF-IDF</strong><ul><li>TF-IDF 결과에서 '동의' 키워드가 2.34의 높은 점수를 받아 토론에서 가장 중요한 키워드임.</li><li>'무고' 키워드의 TF-IDF 점수는 1.27로 '동의'보다는 낮지만 여전히 높은 관심을 받음.</li><li>TF-IDF 분석을 통해 참여자들이 동의와 무고 문제를 중점적으로 다루었음을 확인함.</li><li>높은 TF-IDF 점수를 받은 키워드들이 토론의 핵심 쟁점을 반영함.</li><li>TF-IDF 분석은 토론에서 중요한 주제를 객관적으로 파악하는 데 효과적임.</li></ul></li><li><strong>토론 분석_Text Network</strong><ul><li>텍스트 네트워크 분석에서 '동의' 노드의 중심성이 높아 네트워크 내에서 중요한 위치를 차지함.</li><li>'무고' 노드도 상당한 중심성을 가지고 있어 토론 내에서 핵심적인 역할을 함.</li><li>두 노드 사이의 연결 가중치가 높아 이 키워드들이 토론의 중심 축을 이룸.</li><li>네트워크 분석을 통해 키워드 간 관계와 토론의 흐름을 시각화함.</li><li>참여자들의 의견이 어떻게 연결되고 확산되는지를 분석할 수 있음.</li></ul></li><li><strong>통합 분석</strong><ul><li>LDA, TF-IDF, 텍스트 네트워크 분석을 통합하여 토론의 전반적인 흐름과 주요 쟁점을 파악함.</li><li>'동의'와 '무고'가 모든 분석 방법에서 중요한 위치를 차지하여 이 두 키워드가 토론의 핵심임을 확인함.</li><li>참여자들은 법적 개념 뿐만 아니라 사회적 동의 문화의 정착과 같은 논의를 중시함.</li><li>통합 분석을 통해 토론의 다양한 측면을 종합적으로 이해할 수 있음.</li><li>참여자들의 다양한 의견과 관심사가 복합적으로 반영된 토론의 특성을 파악함.</li></ul></li></ul></li></ol></section><section><h1>IV. 결론 및 제언</h1><ol><li><strong>연구 결과 요약</strong><ul><li>비동의 간음죄 도입에 대한 찬성, 반대, 유보 의견이 존재함.</li><li>참여자들은 법 개정만으로는 해결되지 않는 문제가 많고, 실제 피해자 지원과 피의자 인권 보장 사이 균형이 중요하다고 봄.</li><li>증거 기준의 현실성과 무고 및 악용 우려에 대한 개선 방향이 논의됨.</li><li>사회적으로 동의 문화가 정착되는 것이 중요하며, 법적 논의와 동시에 교육과 캠페인이 필요함.</li><li>디지털 증거의 수집과 보존 절차가 일관되게 설계되어야 함.</li></ul></li><li><strong>의견 변화의 패턴과 원인</strong><ul><li>찬성에서 반대, 유보로의 의견 변화는 주로 법 개정만으로는 해결되지 않는 복잡한 문제와 피해자와 피의자 인권 보호의 균형을 고려한 결과임.</li><li>증거 수집과 보존 절차의 일관성 부재는 양측에 불신을 초래하여 의견 변화의 원인으로 작용함.</li><li>사회적으로 동의 문화 정착과 교육, 캠페인을 병행할 필요성에 대한 인식이 의견 변화를 유도함.</li><li>무고 우려를 줄이기 위한 수사 단계의 사실관계 확인 강화와 동의 기준의 명확성에 대한 논의가 의견 변화의 주요 원인임.</li></ul></li><li><strong>블록체인 기반 공론조사 방법론의 가능성</strong><ul><li>블록체인 기술을 활용한 공론형 여론조사는 개인정보 보호와 익명성을 보장하며, 공정한 정보 제공과 숙고된 토론을 통해 여론의 형성과 변화를 과학적으로 분석할 수 있는 가능성을 보여줌.</li><li>참여자들의 의견을 통해 강간죄 구성요건의 '동의 부재' 기준 전환에 대한 다양한 관점이 수집되었고, 이는 입법 결정의 합리적 참고자료로 활용될 수 있음.</li><li>블록체인의 특성상 조작 방지와 투명성이 보장되어 조사 결과의 신뢰성을 높일 수 있음.</li><li>참여자들의 자발적 참여와 익명성 보장으로 인해 심리적 부담 없이 의견을 표출할 수 있으며, 이는 보다 진정한 여론을 반영할 수 있음.</li><li>블록체인 기반 공론조사는 디지털 증거의 수집과 보존 절차의 일관성을 확보하여 양측의 불신을 최소화할 수 있는 제도 설계의 필요성을 제시함.</li></ul></li></ol></section>"#.to_string()
    });

    let mut editable = use_signal(|| false);

    rsx! {
        div { class: "flex flex-col gap-4",
            button { onclick: move |_| editable.toggle(), "변경" }
            div { "상태 : {editable}" }
            Typo { variant: Variant::H1, weight: Weight::Extrabold, "TIPTAP EDITOR" }
            TiptapEditor {
                class: "w-full h-fit",
                content: content(),
                editable: editable(),
                placeholder: "Type here...",
                on_content_change: move |html: String| {
                    content.set(html);
                },
            }
        }
    }
}
